  static int _storeOptionalError(String? error) => error == null ? 0 : _storeError(error);

  static int _storeError(String error) {
    final bytes = convert.utf8.encode(error);
    final ptr = pkg_ffi.calloc<ffi.Char>(bytes.length);
    try {
      ptr.cast<ffi.Uint8>().asTypedList(bytes.length).setAll(0, bytes);
      return _rpccgoStoreErrorTextRaw(ptr, bytes.length);
    } finally {
      pkg_ffi.calloc.free(ptr);
    }
  }

  static String? _takeErrorResult(int errID) {
    if (errID == 0) return null;
    final textPtr = pkg_ffi.calloc<ffi.UintPtr>();
    final textLen = pkg_ffi.calloc<ffi.Int32>();
    try {
      final status = _rpccgoTakeErrorTextRaw(errID, textPtr, textLen);
      if (status != 0) return 'rpccgo error $errID';
      final data = typed_data.Uint8List.fromList(ffi.Pointer<ffi.Uint8>.fromAddress(textPtr.value).asTypedList(textLen.value));
      _rpccgoReleaseRaw(textPtr.value);
      return convert.utf8.decode(data);
    } finally {
      pkg_ffi.calloc.free(textPtr);
      pkg_ffi.calloc.free(textLen);
    }
  }
}

abstract interface class FlutterDeviceWatchFlutterEchoMessageServerHandler {
  ({pb.FlutterEchoResponse? value, String? error}) Recv();
  String? Finish();
  String? Cancel();
}

